const aiResponse = $input.first().json;
const ratesData = $('Parse Shippo Rates').first().json;

// Basic LLM Chain outputs { output: '...' }
let aiRecommendation = '';
try {
  aiRecommendation = (aiResponse.output || aiResponse.text || '').trim();
} catch (e) {
  aiRecommendation = '推荐选择价格最优且时效较快的承运商';
}

if (!aiRecommendation) {
  aiRecommendation = '推荐选择价格最优且时效较快的承运商';
}

return {
  ...ratesData,
  aiRecommendation
};

